import React, { useEffect, useRef } from 'react';
import './Hero.css';

const Hero = () => {
  const heroStatsRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const stats = entry.target.querySelectorAll('.stat-number');
            stats.forEach((stat) => {
              const target = parseInt(stat.getAttribute('data-target'), 10);
              animateCounter(stat, target);
            });
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.3 }
    );

    if (heroStatsRef.current) {
      observer.observe(heroStatsRef.current);
    }

    return () => observer.disconnect();
  }, []);

  const animateCounter = (el, target, duration = 2000) => {
    let current = 0;
    const increment = target / (duration / 16);
    const timer = setInterval(() => {
      current += increment;
      if (current >= target) {
        el.textContent = target.toLocaleString();
        clearInterval(timer);
      } else {
        el.textContent = Math.floor(current).toLocaleString();
      }
    }, 16);
  };

  return (
    <section className="hero" id="home">
      <div className="hero-blob blob-1" />
      <div className="hero-blob blob-2" />
      <div className="hero-blob blob-3" />

      <div className="container">
        <div className="hero-grid">
          {/* 좌측: 텍스트 & 검색 */}
          <div className="hero-left">
            <div className="hero-badge">
              <span className="badge-icon">🧠</span>
              <span>AI 감정 상담 파트너</span>
            </div>

            <h1 className="hero-title">
              당신의 마음을
              <br />
              <span className="gradient-text">먼저 이해하는 AI</span>
            </h1>

            <p className="hero-subtitle">
              24시간 당신의 곁에서 감정을 나누고,
              <br />
              개인화된 심리 상담을 제공합니다.
            </p>

            <div className="hero-cta">
              <button className="btn-primary">
                <span>무료로 시작하기</span>
                <i className="fas fa-arrow-right" />
              </button>
              <button className="btn-secondary">
                <i className="fas fa-play-circle" />
                <span>데모 보기</span>
              </button>
            </div>

            <div className="hero-features">
              <div className="feature-item">
                <i className="fas fa-check-circle" />
                <span>실시간 감정 분석</span>
              </div>
              <div className="feature-item">
                <i className="fas fa-check-circle" />
                <span>개인화된 상담</span>
              </div>
              <div className="feature-item">
                <i className="fas fa-check-circle" />
                <span>완벽한 프라이버시</span>
              </div>
            </div>
          </div>

          {/* 우측: 비주얼 & 통계 */}
          <div className="hero-right">
            <div className="hero-visual">
              <div className="visual-card">
                <div className="visual-avatar">
                  <span className="avatar-emoji">🤖</span>
                </div>
                <div className="visual-content">
                  <h3>메이티</h3>
                  <p>당신의 AI 친구</p>
                </div>
              </div>

              <div className="visual-chat">
                <div className="chat-bubble ai-bubble">
                  <span>안녕하세요! 오늘 어떤 기분이신가요?</span>
                </div>
                <div className="chat-bubble user-bubble">
                  <span>요즘 좀 힘들어...</span>
                </div>
                <div className="chat-bubble ai-bubble">
                  <span>그렇군요, 얘기해주시겠어요? 🫂</span>
                </div>
              </div>
            </div>

            {/* 통계 카드 */}
            <div className="stats-section" ref={heroStatsRef}>
              <div className="stat-card">
                <div className="stat-icon">💬</div>
                <div className="stat-info">
                  <div className="stat-number" data-target="50000">0</div>
                  <div className="stat-label">월간 대화</div>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-icon">😊</div>
                <div className="stat-info">
                  <div className="stat-number" data-target="98">0</div>
                  <span className="stat-label">% 사용자 만족도</span>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-icon">🌟</div>
                <div className="stat-info">
                  <div className="stat-number" data-target="4.9">0</div>
                  <div className="stat-label">/5 평점</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
